import Project from '@/types/Project';
import ProjectCard from './ProjectCard';
import { Braces } from 'lucide-react';

export default async function ProjectsSection() {
  async function fetchProjects() {
    const response = await fetch(`${process.env.API_URL}/projects`);
    const { data } = await response.json();
    return data;
  }
  const data: Project[] = await fetchProjects();

  return (
    <section
      className="flex h-screen flex-col items-center gap-4 px-10 lg:items-start xl:px-60"
      id="projects"
    >
      <h2 className="flex items-center gap-2">
        <Braces className="scale-105 text-primary transition-all duration-300 hover:scale-110 hover:rotate-6 xl:scale-125" />{' '}
        Projetos
      </h2>

      {data &&
        data.map((project) => (
          <ProjectCard key={project.id} project={project} />
        ))}
    </section>
  );
}
